+            Self::Character => "visual",
+            Self::Line => "visual-line",
+            Self::Block => "visual-block",
+        }
+    }
+}
+
+fn reversed_style() -> Style {
+    Style::default().add_modifier(Modifier::REVERSED)
+}
+
+fn styled_line_spans(line: &str, range: Option<(usize, usize)>) -> Spans<'static> {
+    let Some((start, end)) = range else {
+        return Spans::from(vec![Span::raw(line.to_string())]);
+    };
+    let line_len = line.chars().count();
+    let start = start.min(line_len);
+    let end = end.min(line_len);
+    if start >= end {
+        return Spans::from(vec![Span::raw(line.to_string())]);
+    }
+
+    let start_byte = byte_index_for_char(line, start);
+    let end_byte = byte_index_for_char(line, end);
+    let mut spans = Vec::new();
+    if start_byte > 0 {
+        spans.push(Span::raw(line[..start_byte].to_string()));
+    }
+    spans.push(Span::styled(
+        line[start_byte..end_byte].to_string(),
+        reversed_style(),
+    ));
+    if end_byte < line.len() {
+        spans.push(Span::raw(line[end_byte..].to_string()));
+    }
+    Spans::from(spans)
+}
+
+fn selected_ranges(
+    lines: &[String],
+    selection: &VisualSelection,
+    force_line: bool,
+) -> Vec<Option<(usize, usize)>> {
+    let mut ranges = vec![None; lines.len()];
+    if lines.is_empty() {
+        return ranges;
+    }
+
+    let start_line = selection.anchor.line.min(selection.cursor.line);
+    let end_line = selection
+        .anchor
+        .line
+        .max(selection.cursor.line)
+        .min(lines.len() - 1);
+    let mode = if force_line {
+        VisualSelectionMode::Line
+    } else {
+        selection.mode
+    };
+
+    match mode {
+        VisualSelectionMode::Line => {
+            for line_index in start_line..=end_line {
+                ranges[line_index] = Some((0, lines[line_index].chars().count()));
+            }
+        }
+        VisualSelectionMode::Block => {
+            let start_column = selection.anchor.column.min(selection.cursor.column);
+            let end_column = selection.anchor.column.max(selection.cursor.column);
+            for line_index in start_line..=end_line {
+                let line_len = lines[line_index].chars().count();
+                let start = start_column.min(line_len);
+                let end = end_column.saturating_add(1).min(line_len);
+                ranges[line_index] = Some((start, end));
+            }
+        }
+        VisualSelectionMode::Character => {
+            let (start, end) = ordered_cursors(selection.anchor, selection.cursor);
+            let start_line = start.line.min(lines.len() - 1);
+            let end_line = end.line.min(lines.len() - 1);
+            if start_line == end_line {
+                let line_len = lines[start_line].chars().count();
+                ranges[start_line] = Some((
+                    start.column.min(line_len),
+                    end.column.saturating_add(1).min(line_len),
+                ));
+            } else {
+                for line_index in start_line..=end_line {
+                    let line_len = lines[line_index].chars().count();
+                    ranges[line_index] = if line_index == start_line {
+                        Some((start.column.min(line_len), line_len))
+                    } else if line_index == end_line {
+                        Some((0, end.column.saturating_add(1).min(line_len)))
+                    } else {
+                        Some((0, line_len))
+                    };
+                }
+            }
+        }
+    }
+
+    ranges
+}
+
+fn selected_text(lines: &[String], selection: &VisualSelection, force_line: bool) -> String {
+    let ranges = selected_ranges(lines, selection, force_line);
+    ranges
+        .into_iter()
+        .enumerate()
+        .filter_map(|(index, range)| {
+            range.map(|(start, end)| slice_chars(&lines[index], start, end))
+        })
+        .collect::<Vec<_>>()
+        .join("\n")
+}
+
+fn ordered_cursors(left: TextCursor, right: TextCursor) -> (TextCursor, TextCursor) {
+    if (left.line, left.column) <= (right.line, right.column) {
+        (left, right)
+    } else {
+        (right, left)
+    }
+}
+
+fn slice_chars(text: &str, start: usize, end: usize) -> String {
+    let start = start.min(text.chars().count());
+    let end = end.min(text.chars().count());
+    text.chars()
+        .skip(start)
+        .take(end.saturating_sub(start))
+        .collect()
+}
+
+fn byte_index_for_char(text: &str, char_index: usize) -> usize {
+    text.char_indices()
+        .nth(char_index)
+        .map(|(index, _)| index)
+        .unwrap_or(text.len())
+}
