548	    fn begin_visual_selection(&mut self, mode: VisualSelectionMode, right_content: &str) {
549	        let focus = self.focus;
550	        let lines = self.selection_lines(focus, right_content);
551	        let cursor = self.initial_visual_cursor(focus, &lines);
552	        self.mode = UiMode::Command;
553	        self.pending = None;
554	        self.visual_selection = Some(VisualSelection {
555	            focus,
556	            mode,
557	            anchor: cursor,
558	            cursor,
559	        });
560	    }
561	
562	    fn switch_visual_selection_mode(&mut self, mode: VisualSelectionMode, right_content: &str) {
563	        let Some(selection) = self.visual_selection.as_mut() else {
564	            self.begin_visual_selection(mode, right_content);
565	            return;
566	        };
567	        selection.mode = mode;
568	        self.clamp_visual_selection(right_content);
569	    }
570	
571	    fn move_visual_cursor(&mut self, line_delta: isize, column_delta: isize, right_content: &str) {
572	        let Some(selection) = self.visual_selection.as_ref() else {
573	            return;
574	        };
575	        let lines = self.selection_lines(selection.focus, right_content);
576	        let max_line = lines.len().saturating_sub(1);
577	
578	        let Some(selection) = self.visual_selection.as_mut() else {
579	            return;
580	        };
581	        selection.cursor.line = selection
582	            .cursor
583	            .line
584	            .saturating_add_signed(line_delta)
585	            .min(max_line);
586	
587	        let current_line_len = lines
588	            .get(selection.cursor.line)
589	            .map(|line| line.chars().count().saturating_sub(1))
590	            .unwrap_or_default();
591	        selection.cursor.column = selection
592	            .cursor
593	            .column
594	            .saturating_add_signed(column_delta)
595	            .min(current_line_len);
596	    }
